"use strict";(self.webpackChunkroadmap_sy=self.webpackChunkroadmap_sy||[]).push([[567],{5226:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","label":"Getting Started","href":"/","docId":"getting-started","unlisted":false},{"type":"category","label":"Core Skills","items":[{"type":"link","label":"Web","href":"/web","docId":"web","unlisted":false},{"type":"link","label":"Git","href":"/git","docId":"git","unlisted":false},{"type":"link","label":"Testing","href":"/testing","docId":"testing","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Deployment & Production","items":[{"type":"link","label":"Containerization","href":"/containerization","docId":"containerization","unlisted":false},{"type":"link","label":"CI/CD","href":"/ci-cd","docId":"ci-cd","unlisted":false},{"type":"link","label":"Observability","href":"/observability","docId":"observability","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Learn by Doing","items":[{"type":"link","label":"Open Source","href":"/open-source","docId":"open-source","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Learn from Others","items":[{"type":"link","label":"Mentorship","href":"/mentorship","docId":"mentorship","unlisted":false},{"type":"link","label":"Global Communities","href":"/global-communities","docId":"global-communities","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"ci-cd":{"id":"ci-cd","title":"CI/CD","description":"You know about CI/CD pipelines, but your current team does manual deployments. One person runs tests, builds the app, and pushes to production. It\'s slow but manageable for your small team. But as teams grow and deployment frequency increases, manual processes become too difficult and lead to mistakes. You realize that while manual deployments work for small teams, most professional environments expect automated pipelines.","sidebar":"tutorialSidebar"},"containerization":{"id":"containerization","title":"Containerization","description":"You\'ve heard about Docker and containers, but your current setup is simple\u2014you develop locally and deploy to a single server that the DevOps person manages. It works fine for your current project. But as soon as you need to scale, work with multiple environments, or collaborate with larger teams, environment consistency becomes important. You realize that while you can avoid containers in simple environments, most modern development teams use them. It\'s time to learn containerization.","sidebar":"tutorialSidebar"},"getting-started":{"id":"getting-started","title":"Getting Started","description":"What is Dev Rebase?","sidebar":"tutorialSidebar"},"git":{"id":"git","title":"Git","description":"You know Git exists, you\'ve even used basic commands, but your current team is small and everyone just pushes to main. No branches, no pull requests, no complex workflows. It works fine for your current project. But the moment you join a larger team or work on a more complex project, proper Git workflows become essential for preventing problems and maintaining code quality. You realize that while simple Git works for small teams, understanding proper Git workflows is essential for most professional development environments. It\'s time to master Git properly.","sidebar":"tutorialSidebar"},"global-communities":{"id":"global-communities","title":"Global Communities","description":"Building a successful tech career is not just about your technical skills\u2014it\'s about connecting with the right communities that can guide you, support you, and open doors to opportunities you might never find on your own. By joining global tech communities, you gain access to resources that can help you grow professionally, find international opportunities, and connect with others who share similar experiences and goals.","sidebar":"tutorialSidebar"},"mentorship":{"id":"mentorship","title":"Mentorship","description":"You have worked hard on tutorials, built your own projects, and maybe even got your first job as a developer. But sometimes you face problems that are very hard to solve by yourself. Maybe you are confused about how to make big decisions in your code, how to grow in your career, or what to learn next. Having someone with more experience to guide you can really help. In today\'s fast-changing tech world, having a mentor is not just useful\u2014it can be the difference between growing as a developer or feeling stuck and alone.","sidebar":"tutorialSidebar"},"observability":{"id":"observability","title":"Observability","description":"You\'ve heard about monitoring, logging, and metrics, but your current application is simple enough that you can usually figure out problems by looking at the code or asking users what went wrong. But as your application serves more users and becomes more complex, debugging production issues without proper observability becomes nearly impossible. You realize that while you can manage simple applications without observability, most professional environments require it. It\'s time to make your applications observable.","sidebar":"tutorialSidebar"},"open-source":{"id":"open-source","title":"Open Source","description":"Contributing to open source is one of the best ways to grow as a developer, build your reputation, and connect with developers around the world. Open source gives you a way to show your skills to international employers and build professional relationships across borders.","sidebar":"tutorialSidebar"},"testing":{"id":"testing","title":"Testing","description":"You\'ve heard about unit tests, integration tests, and TDD, but your current company has a dedicated QA team that handles all testing. You write code, they test it, and that system works fine. But as applications grow more complex and teams move faster, relying only on manual testing becomes a bottleneck that slows everyone down. You realize that while you can rely on QA teams in some companies, most modern development roles expect you to test your own code. It\'s time to start testing your own code.","sidebar":"tutorialSidebar"},"web":{"id":"web","title":"Web","description":"You\'ve always focused on writing good code. You build beautiful components, create smooth user experiences, or develop clean APIs. Your current job keeps things simple: you build features, someone else handles deployment, and if there are network issues, the backend team deals with them.","sidebar":"tutorialSidebar"}}}}')}}]);